import{_ as s,o as e,c as n,a2 as l}from"./chunks/framework.DRBHoC6Q.js";const b=JSON.parse('{"title":"30 / 60 / 90 天现金流预测模块 MVP 技术方案初稿","description":"","frontmatter":{},"headers":[],"relativePath":"modules/cashflow.md","filePath":"modules/cashflow.md","lastUpdated":1783323851000}'),i={name:"modules/cashflow.md"};function t(p,a,d,r,c,o){return e(),n("div",null,[...a[0]||(a[0]=[l(`<h1 id="_30-60-90-天现金流预测模块-mvp-技术方案初稿" tabindex="-1">30 / 60 / 90 天现金流预测模块 MVP 技术方案初稿 <a class="header-anchor" href="#_30-60-90-天现金流预测模块-mvp-技术方案初稿" aria-label="Permalink to &quot;30 / 60 / 90 天现金流预测模块 MVP 技术方案初稿&quot;">​</a></h1><p>文档版本：V0.1<br> 状态：讨论稿，计算口径待产品与财务确认<br> 目标读者：产品、财务、后端开发和测试人员</p><h2 id="_1-模块目标" tabindex="-1">1. 模块目标 <a class="header-anchor" href="#_1-模块目标" aria-label="Permalink to &quot;1. 模块目标&quot;">​</a></h2><p>本模块基于已发布的财务基础数据，按天计算未来 90 天的预测现金余额，并回答以下问题：</p><ul><li>未来 30、60、90 天内是否会出现现金缺口；</li><li>每个时间窗口内的最大现金缺口是多少；</li><li>最大缺口最早在哪一天出现；</li><li>现金何时跌破或恢复现金安全线；</li><li>哪些预计回款和计划支出是缺口的主要影响因素。</li></ul><p>MVP 中所有金额和日期由确定性规则计算。AI 不参与数值预测，只能在计算完成后解释原因和组织文字。</p><h2 id="_2-mvp-范围" tabindex="-1">2. MVP 范围 <a class="header-anchor" href="#_2-mvp-范围" aria-label="Permalink to &quot;2. MVP 范围&quot;">​</a></h2><h3 id="_2-1-本期实现" tabindex="-1">2.1 本期实现 <a class="header-anchor" href="#_2-1-本期实现" aria-label="Permalink to &quot;2.1 本期实现&quot;">​</a></h3><ul><li>生成从计算基准日开始、未来 90 天的每日现金余额序列；</li><li>计算 30、60、90 天三个累计窗口的最大缺口；</li><li>返回最低余额、缺口日期、首次跌破安全线日期和恢复日期；</li><li>保留参与计算的应收和支出记录，支持结果追溯。</li></ul><h3 id="_2-2-本期不实现" tabindex="-1">2.2 本期不实现 <a class="header-anchor" href="#_2-2-本期不实现" aria-label="Permalink to &quot;2.2 本期不实现&quot;">​</a></h3><ul><li>使用大模型生成回款金额或支出金额；</li><li>根据历史规律自动预测没有计划日期的数据；</li><li>概率预测、置信区间和多情景模拟；</li><li>融资额度、授信、税费、汇率和集团内部资金调拨；</li><li>复杂预算控制和会计利润预测。</li></ul><h2 id="_3-数据输入" tabindex="-1">3. 数据输入 <a class="header-anchor" href="#_3-数据输入" aria-label="Permalink to &quot;3. 数据输入&quot;">​</a></h2><p>MVP 使用四类基础事实数据。</p><table tabindex="0"><thead><tr><th>数据</th><th>用途</th><th>关键字段</th></tr></thead><tbody><tr><td>账户余额</td><td>确定预测起点的可用现金</td><td>账户、快照日期、可用余额、状态</td></tr><tr><td>应收款</td><td>确定未来可能到账的金额和日期</td><td>应收金额、预计到账日、约定到账日、状态</td></tr><tr><td>实际回款</td><td>计算每笔应收尚未到账的余额</td><td>关联应收、回款日期、回款金额、状态</td></tr><tr><td>计划支出</td><td>确定未来计划流出的金额和日期</td><td>计划日期、计划金额、审批状态、状态</td></tr></tbody></table><h3 id="_3-1-计算基准日" tabindex="-1">3.1 计算基准日 <a class="header-anchor" href="#_3-1-计算基准日" aria-label="Permalink to &quot;3.1 计算基准日&quot;">​</a></h3><p>每次计算必须指定 <code>asOfDate</code>，表示“站在哪一天看未来”。本文记为 <code>D</code>。</p><p>所有输入数据必须来自同一个已发布数据批次。未发布、已作废或校验失败的数据不得参与正式计算。</p><h3 id="_3-2-期初可用现金" tabindex="-1">3.2 期初可用现金 <a class="header-anchor" href="#_3-2-期初可用现金" aria-label="Permalink to &quot;3.2 期初可用现金&quot;">​</a></h3><p>对每个有效账户，取不晚于 <code>D</code> 的最新一条余额快照：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>账户期初余额 = 该账户 snapshot_date &lt;= D 的最新 available_balance</span></span>
<span class="line"><span>期初可用现金 = Σ 所有有效账户的账户期初余额</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>如果任何有效账户在 <code>D</code> 之前没有余额快照，结果必须返回数据缺失警告。</p><h3 id="_3-3-应收未回金额" tabindex="-1">3.3 应收未回金额 <a class="header-anchor" href="#_3-3-应收未回金额" aria-label="Permalink to &quot;3.3 应收未回金额&quot;">​</a></h3><p>先按应收款汇总有效实际回款：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>累计实际回款 = Σ 关联到该应收的有效回款金额</span></span>
<span class="line"><span>应收未回金额 = max(应收金额 - 累计实际回款, 0)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>累计实际回款大于应收金额时，未回金额仍按 0 处理，同时返回“可能存在超额回款”的数据警告。</p><h3 id="_3-4-有效预计回款日期" tabindex="-1">3.4 有效预计回款日期 <a class="header-anchor" href="#_3-4-有效预计回款日期" aria-label="Permalink to &quot;3.4 有效预计回款日期&quot;">​</a></h3><p>MVP 的日期选择规则：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>如果 expected_date 存在：有效预计回款日期 = expected_date</span></span>
<span class="line"><span>否则：有效预计回款日期 = agreed_due_date</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>只有同时满足以下条件的应收未回金额才进入基础预测：</p><ul><li>应收记录有效且处于未关闭状态；</li><li>应收未回金额大于 0；</li><li>有效预计回款日期位于 <code>[D, D + 89 天]</code>；</li><li>有效预计回款日期没有早于计算基准日。</li></ul><p>已逾期且没有新的未来预计到账日期的应收，不得假设在今天或明天到账。该金额单独标记为“逾期待确认回款”，不进入基础预测现金流。</p><h3 id="_3-5-有效计划支出" tabindex="-1">3.5 有效计划支出 <a class="header-anchor" href="#_3-5-有效计划支出" aria-label="Permalink to &quot;3.5 有效计划支出&quot;">​</a></h3><p>计划支出同时满足以下条件时进入预测：</p><ul><li>记录有效；</li><li>计划日期位于 <code>[D, D + 89 天]</code>；</li><li>审批状态属于 <code>planned</code>、<code>pending</code> 或 <code>approved</code>；</li><li>未被标记为已支付或已取消。</li></ul><p>MVP 当前没有独立的实际付款表，因此系统无法通过真实付款记录自动扣除已经支付的计划。数据提供方必须及时更新计划支出状态，否则可能重复计算支出。这一限制必须随结果返回。</p><h2 id="_4-逐日现金流计算" tabindex="-1">4. 逐日现金流计算 <a class="header-anchor" href="#_4-逐日现金流计算" aria-label="Permalink to &quot;4. 逐日现金流计算&quot;">​</a></h2><h3 id="_4-1-计算日期范围" tabindex="-1">4.1 计算日期范围 <a class="header-anchor" href="#_4-1-计算日期范围" aria-label="Permalink to &quot;4.1 计算日期范围&quot;">​</a></h3><p>生成 90 个自然日的计算点：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>D, D+1, D+2, ..., D+89</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="_4-2-每日流入" tabindex="-1">4.2 每日流入 <a class="header-anchor" href="#_4-2-每日流入" aria-label="Permalink to &quot;4.2 每日流入&quot;">​</a></h3><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>第 t 日预计流入</span></span>
<span class="line"><span>= Σ 有效预计回款日期等于第 t 日的应收未回金额</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h3 id="_4-3-每日流出" tabindex="-1">4.3 每日流出 <a class="header-anchor" href="#_4-3-每日流出" aria-label="Permalink to &quot;4.3 每日流出&quot;">​</a></h3><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>第 t 日计划流出</span></span>
<span class="line"><span>= Σ 计划日期等于第 t 日的有效计划支出金额</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h3 id="_4-4-每日净现金流" tabindex="-1">4.4 每日净现金流 <a class="header-anchor" href="#_4-4-每日净现金流" aria-label="Permalink to &quot;4.4 每日净现金流&quot;">​</a></h3><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>第 t 日净现金流 = 第 t 日预计流入 - 第 t 日计划流出</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="_4-5-每日预测余额" tabindex="-1">4.5 每日预测余额 <a class="header-anchor" href="#_4-5-每日预测余额" aria-label="Permalink to &quot;4.5 每日预测余额&quot;">​</a></h3><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>第 0 日预测余额 = 期初可用现金 + 第 0 日净现金流</span></span>
<span class="line"><span>第 t 日预测余额 = 第 t-1 日预测余额 + 第 t 日净现金流</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>同一天发生多笔回款和支出时，MVP 按当日净额计算，不区分日内发生顺序。</p><h2 id="_5-30-60-90-天窗口定义" tabindex="-1">5. 30 / 60 / 90 天窗口定义 <a class="header-anchor" href="#_5-30-60-90-天窗口定义" aria-label="Permalink to &quot;5. 30 / 60 / 90 天窗口定义&quot;">​</a></h2><p>三个窗口均从 <code>D</code> 开始，属于累计窗口：</p><table tabindex="0"><thead><tr><th>窗口</th><th>日期范围</th></tr></thead><tbody><tr><td>30 天</td><td><code>D</code> 至 <code>D+29</code></td></tr><tr><td>60 天</td><td><code>D</code> 至 <code>D+59</code></td></tr><tr><td>90 天</td><td><code>D</code> 至 <code>D+89</code></td></tr></tbody></table><p>页面展示的是窗口内曾经出现过的最大缺口，不是第 30、60、90 天当天的余额。</p><p>对任一窗口 <code>W</code>：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>窗口最低余额 = min(窗口内每日预测余额)</span></span>
<span class="line"><span>窗口最大缺口 = max(现金安全线 - 窗口最低余额, 0)</span></span>
<span class="line"><span>缺口出现日期 = 最早达到窗口最低余额的日期</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>MVP 默认现金安全线为 0 元：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>窗口最大缺口 = max(-窗口最低余额, 0)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>采用窗口内最低余额，可以发现中途资金断点。例如第 20 天余额为负、第 30 天因回款恢复为正时，30 天窗口仍会正确显示曾经出现的缺口。</p><h3 id="_5-1-企业现金流规划中的产品口径" tabindex="-1">5.1 企业现金流规划中的产品口径 <a class="header-anchor" href="#_5-1-企业现金流规划中的产品口径" aria-label="Permalink to &quot;5.1 企业现金流规划中的产品口径&quot;">​</a></h3><p>企业通常不是分别建立“30 天模型”“60 天模型”和“90 天模型”，而是建立一条持续更新的滚动现金流预测，再从同一条预测曲线观察不同时间窗口。</p><p>本模块也采用这一方式：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>四类基础事实数据</span></span>
<span class="line"><span>→ 生成未来 90 天逐日预测余额</span></span>
<span class="line"><span>→ 从同一条余额曲线截取 30、60、90 天累计窗口</span></span>
<span class="line"><span>→ 计算各窗口最低余额和最大缺口</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>三个窗口存在包含关系：60 天包含前 30 天，90 天包含前 60 天。因此三个缺口数字可能相同，也可能随着远期支出加入而逐步增大。它们不是三个互相独立的预测结论。</p><p>同时，预测距离越远，数据可靠性通常越低：</p><ul><li>未来 30 天的回款和支出计划相对明确，可作为短期资金调度依据；</li><li>31～60 天主要用于观察已知计划带来的资金压力；</li><li>61～90 天更适合判断趋势，不宜表达为与 30 天结果同等精确的承诺。</li></ul><h3 id="_5-2-首页展示建议" tabindex="-1">5.2 首页展示建议 <a class="header-anchor" href="#_5-2-首页展示建议" aria-label="Permalink to &quot;5.2 首页展示建议&quot;">​</a></h3><p>从老板决策视角看，同时突出三个“缺口金额”不一定是最容易理解的表达。MVP 后端仍应完整返回 30、60、90 天窗口结果，便于核对和后续扩展；首页建议优先突出：</p><ul><li>未来 90 天最大现金缺口；</li><li>最大缺口出现日期；</li><li>预计恢复安全线日期；</li><li>一条未来 90 天预测余额曲线。</li></ul><p>如果产品必须保留三张窗口卡片，建议增加口径标签：</p><table tabindex="0"><thead><tr><th>窗口</th><th>建议表达</th></tr></thead><tbody><tr><td>30 天</td><td>高可信短期预测</td></tr><tr><td>60 天</td><td>计划预测</td></tr><tr><td>90 天</td><td>趋势判断</td></tr></tbody></table><p>最终页面采用“三个窗口缺口”还是“最大缺口 + 日期 + 恢复时间”，属于产品展示决策，不改变底层逐日计算逻辑。</p><h2 id="_6-安全线与恢复日期" tabindex="-1">6. 安全线与恢复日期 <a class="header-anchor" href="#_6-安全线与恢复日期" aria-label="Permalink to &quot;6. 安全线与恢复日期&quot;">​</a></h2><p>MVP 默认：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>现金安全线 = 0 元</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>派生日期定义如下：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>首次跌破安全线日期</span></span>
<span class="line"><span>= 预测余额第一次小于现金安全线的日期</span></span>
<span class="line"><span></span></span>
<span class="line"><span>恢复安全线日期</span></span>
<span class="line"><span>= 跌破后预测余额第一次重新大于等于现金安全线，且此后不再跌破的日期</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>如果 90 天内没有恢复，返回空值并标记“90 天内未恢复”。后续版本可以把安全线升级为固定金额或未来若干天的刚性支出，但不进入当前 MVP。</p><h2 id="_7-主要影响因素" tabindex="-1">7. 主要影响因素 <a class="header-anchor" href="#_7-主要影响因素" aria-label="Permalink to &quot;7. 主要影响因素&quot;">​</a></h2><p>主要影响因素必须来自参与计算的真实记录，不由 AI 编造。</p><p>MVP 可按以下方式筛选：</p><ul><li>缺口日期之前未按计划到账的逾期应收，按未回金额降序；</li><li>缺口日期当日及之前的计划支出，按计划金额降序；</li><li>分别最多返回 3 笔预计回款和 3 笔计划支出。</li></ul><p>计算引擎返回结构化记录及金额，AI 可以据此生成“主要原因”和“建议动作”的自然语言说明，但不得修改金额、日期和关联记录。</p><h2 id="_8-计算示例" tabindex="-1">8. 计算示例 <a class="header-anchor" href="#_8-计算示例" aria-label="Permalink to &quot;8. 计算示例&quot;">​</a></h2><p>假设计算基准日为 7 月 5 日：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>期初可用现金：500 万元</span></span>
<span class="line"><span>7 月 10 日预计回款：300 万元</span></span>
<span class="line"><span>7 月 15 日计划支出：400 万元</span></span>
<span class="line"><span>7 月 25 日计划支出：600 万元</span></span>
<span class="line"><span>8 月 20 日预计回款：500 万元</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>逐日关键结果：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>7 月 5 日：500 万元</span></span>
<span class="line"><span>7 月 10 日：800 万元</span></span>
<span class="line"><span>7 月 15 日：400 万元</span></span>
<span class="line"><span>7 月 25 日：-200 万元</span></span>
<span class="line"><span>8 月 20 日：300 万元</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>因此：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>30 天窗口最低余额：-200 万元</span></span>
<span class="line"><span>30 天最大缺口：200 万元</span></span>
<span class="line"><span>缺口出现日期：7 月 25 日</span></span>
<span class="line"><span>60 天窗口最低余额：-200 万元</span></span>
<span class="line"><span>60 天最大缺口：200 万元</span></span>
<span class="line"><span>恢复安全线日期：8 月 20 日</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>这个例子说明：窗口结果必须基于每日累计余额，而不是简单使用“窗口总收入减窗口总支出”。</p><h2 id="_9-输出结果最低要求" tabindex="-1">9. 输出结果最低要求 <a class="header-anchor" href="#_9-输出结果最低要求" aria-label="Permalink to &quot;9. 输出结果最低要求&quot;">​</a></h2><p>计算结果至少包含：</p><ul><li>计算基准日和 90 天日期范围；</li><li>数据批次和规则版本；</li><li>期初可用现金；</li><li>30、60、90 天窗口的最低余额、最大缺口和缺口日期；</li><li>首次跌破安全线日期和恢复安全线日期；</li><li>90 天每日预计流入、计划流出、净现金流和预测余额；</li><li>主要影响因素及其来源记录；</li><li>未进入预测的逾期待确认回款金额；</li><li>数据缺失、超额回款和支出状态不完整等警告。</li></ul><p>金额必须使用十进制定点计算，禁止使用二进制浮点数直接计算财务金额。</p><h2 id="_10-mvp-验收标准" tabindex="-1">10. MVP 验收标准 <a class="header-anchor" href="#_10-mvp-验收标准" aria-label="Permalink to &quot;10. MVP 验收标准&quot;">​</a></h2><ul><li>相同数据批次、基准日和规则版本必须得到完全相同的结果；</li><li>任一窗口的最大缺口能够追溯到每日余额和具体业务记录；</li><li>已实际回款金额不会再次作为未来回款重复计入；</li><li>已逾期且没有新预计日期的应收不会被自动假设到账；</li><li>已取消的计划支出不会进入预测；</li><li>30、60、90 天结果取各自窗口内最低余额，而不是窗口最后一天余额；</li><li>财务可以使用同一批样本数据手工复算并得到一致结果。</li></ul><h2 id="_11-待确认口径" tabindex="-1">11. 待确认口径 <a class="header-anchor" href="#_11-待确认口径" aria-label="Permalink to &quot;11. 待确认口径&quot;">​</a></h2><p>以下事项不阻塞初稿，但在上线真实数据前必须确认：</p><ol><li><code>expected_date</code> 是否允许业务人员持续更新；</li><li>已逾期应收是否全部排除，还是允许应用统一可信折扣；</li><li>计划支出哪些审批状态应进入预测；</li><li>实际付款数据缺失时，如何确认计划支出已经支付；</li><li>安全线是否长期使用 0 元，还是改为财务配置金额；</li><li>同一天资金流入和流出是否需要考虑日内先后顺序；</li><li>首页最终采用三个窗口缺口卡片，还是“最大缺口、出现日期、恢复日期”的决策型表达。</li></ol>`,98)])])}const u=s(i,[["render",t]]);export{b as __pageData,u as default};
